SELECT c.id, c.member_id, m.name AS member_name, m.phone AS member_phone, c.checkin_time, c.checkout_time, c.status, c.type, c.course_id, co.course_name, c.coach_id, u.username AS coach_name, c.remark, TIMESTAMPDIFF(MINUTE, c.checkin_time, IFNULL(c.checkout_time, NOW())) AS duration FROM checkin c LEFT JOIN member m ON c.member_id = m.id LEFT JOIN course co ON c.course_id = co.id LEFT JOIN user u ON c.coach_id = u.id
AND c.member_id = #{memberId}
AND c.coach_id = #{coachId}
AND c.course_id = #{courseId}
AND c.status = #{status}
AND c.type = #{type}
AND c.checkin_time >= #{startTime}
AND c.checkin_time <= #{endTime}
ORDER BY c.checkin_time DESC

SELECT c.id, c.member_id, m.name AS member_name, m.phone AS member_phone, c.checkin_time, c.checkout_time, c.status, c.type, c.course_id, co.course_name, c.coach_id, u.username AS coach_name, c.remark, TIMESTAMPDIFF(MINUTE, c.checkin_time, IFNULL(c.checkout_time, NOW())) AS duration FROM checkin c LEFT JOIN member m ON c.member_id = m.id LEFT JOIN course co ON c.course_id = co.id LEFT JOIN user u ON c.coach_id = u.id WHERE c.member_id = #{memberId}
AND c.status = #{status}
ORDER BY c.checkin_time DESC
